"""Launch Interceptor Program — DECIDE (Knight & Leveson, 1986)."""

from __future__ import annotations

import math
from typing import Any, Dict, List, Tuple

PI = 3.1415926535


def realcompare(a: float, b: float) -> str:
    """Compare two reals using six significant digits (per spec)."""

    def round_sig6(x: float) -> float:
        if x == 0.0:
            return 0.0
        e = math.floor(math.log10(abs(x)))
        d = 5 - int(e)
        return round(x, d)

    ra, rb = round_sig6(a), round_sig6(b)
    if ra < rb:
        return "LT"
    if ra > rb:
        return "GT"
    return "EQ"


def _dist(x1: float, y1: float, x2: float, y2: float) -> float:
    return math.hypot(x2 - x1, y2 - y1)


def _triangle_area(x1: float, y1: float, x2: float, y2: float, x3: float, y3: float) -> float:
    return 0.5 * abs((x2 - x1) * (y3 - y1) - (x3 - x1) * (y2 - y1))


def _min_circle_radius_three(
    x1: float, y1: float, x2: float, y2: float, x3: float, y3: float
) -> float:
    """Smallest circle radius containing three planar points."""
    a = _dist(x2, y2, x3, y3)
    b = _dist(x1, y1, x3, y3)
    c = _dist(x1, y1, x2, y2)
    area = _triangle_area(x1, y1, x2, y2, x3, y3)
    if realcompare(area, 0.0) == "EQ":
        return max(a, b, c) / 2.0
    d1 = (x2 - x1) * (x3 - x1) + (y2 - y1) * (y3 - y1)
    d2 = (x1 - x2) * (x3 - x2) + (y1 - y2) * (y3 - y2)
    d3 = (x1 - x3) * (x2 - x3) + (y1 - y3) * (y2 - y3)
    if realcompare(d1, 0.0) != "GT":
        return a / 2.0
    if realcompare(d2, 0.0) != "GT":
        return b / 2.0
    if realcompare(d3, 0.0) != "GT":
        return c / 2.0
    return (a * b * c) / (4.0 * area)


def _three_points_in_disk(
    x1: float, y1: float, x2: float, y2: float, x3: float, y3: float, radius: float
) -> bool:
    r = _min_circle_radius_three(x1, y1, x2, y2, x3, y3)
    cmp_r = realcompare(r, radius)
    return cmp_r == "LT" or cmp_r == "EQ"


def _quadrant(x: float, y: float) -> int:
    if realcompare(x, 0.0) == "GT":
        if realcompare(y, 0.0) == "GT":
            return 1
        if realcompare(y, 0.0) == "EQ":
            return 1
        return 4
    if realcompare(x, 0.0) == "EQ":
        if realcompare(y, 0.0) == "GT":
            return 1
        if realcompare(y, 0.0) == "EQ":
            return 1
        return 3
    if realcompare(y, 0.0) == "GT":
        return 2
    if realcompare(y, 0.0) == "EQ":
        return 2
    return 3


def _angle_at_vertex(
    ax: float, ay: float, vx: float, vy: float, bx: float, by: float
) -> float:
    v1x, v1y = ax - vx, ay - vy
    v2x, v2y = bx - vx, by - vy
    cross = v1x * v2y - v1y * v2x
    dot = v1x * v2x + v1y * v2y
    return math.atan2(abs(cross), dot)


def _lic1(x: List[float], y: List[float], n: int, length1: float) -> bool:
    for i in range(n - 1):
        d = _dist(x[i], y[i], x[i + 1], y[i + 1])
        if realcompare(d, length1) == "GT":
            return True
    return False


def _lic2(x: List[float], y: List[float], n: int, radius1: float) -> bool:
    for i in range(n - 2):
        r = _min_circle_radius_three(x[i], y[i], x[i + 1], y[i + 1], x[i + 2], y[i + 2])
        if realcompare(r, radius1) == "GT":
            return True
    return False


def _lic3(x: List[float], y: List[float], n: int, epsilon: float) -> bool:
    for i in range(n - 2):
        ax, ay = x[i], y[i]
        vx, vy = x[i + 1], y[i + 1]
        bx, by = x[i + 2], y[i + 2]
        if (
            realcompare(ax, vx) == "EQ"
            and realcompare(ay, vy) == "EQ"
            or realcompare(bx, vx) == "EQ"
            and realcompare(by, vy) == "EQ"
        ):
            continue
        ang = _angle_at_vertex(ax, ay, vx, vy, bx, by)
        if realcompare(ang, PI - epsilon) == "LT" or realcompare(ang, PI + epsilon) == "GT":
            return True
    return False


def _lic4(x: List[float], y: List[float], n: int, area1: float) -> bool:
    for i in range(n - 2):
        a = _triangle_area(x[i], y[i], x[i + 1], y[i + 1], x[i + 2], y[i + 2])
        if realcompare(a, area1) == "GT":
            return True
    return False


def _lic5(x: List[float], y: List[float], n: int, q_pts: int, quads: int) -> bool:
    for start in range(n - q_pts + 1):
        seen = set()
        for j in range(start, start + q_pts):
            seen.add(_quadrant(x[j], y[j]))
        if len(seen) > quads:
            return True
    return False


def _lic6(x: List[float], y: List[float], n: int) -> bool:
    for i in range(n - 1):
        if realcompare(x[i + 1] - x[i], 0.0) == "LT":
            return True
    return False


def _lic7(x: List[float], y: List[float], n: int, n_pts: int, dist_param: float) -> bool:
    if n < 3:
        return False
    for start in range(n - n_pts + 1):
        x0, y0 = x[start], y[start]
        x1, y1 = x[start + n_pts - 1], y[start + n_pts - 1]
        if realcompare(x0, x1) == "EQ" and realcompare(y0, y1) == "EQ":
            for j in range(start + 1, start + n_pts - 1):
                d = _dist(x[j], y[j], x0, y0)
                if realcompare(d, dist_param) == "GT":
                    return True
        else:
            dx, dy = x1 - x0, y1 - y0
            base = math.hypot(dx, dy)
            for j in range(start + 1, start + n_pts - 1):
                px, py = x[j], y[j]
                d = abs(dx * (y0 - py) - dy * (x0 - px)) / base
                if realcompare(d, dist_param) == "GT":
                    return True
    return False


def _lic8(x: List[float], y: List[float], n: int, k_pts: int, length1: float) -> bool:
    if n < 3:
        return False
    for i in range(n - k_pts - 1):
        j = i + k_pts + 1
        d = _dist(x[i], y[i], x[j], y[j])
        if realcompare(d, length1) == "GT":
            return True
    return False


def _lic9(x: List[float], y: List[float], n: int, a_pts: int, b_pts: int, radius1: float) -> bool:
    if n < 5:
        return False
    for i in range(n - a_pts - b_pts - 2):
        i2 = i + a_pts + 1
        i3 = i + a_pts + b_pts + 2
        if not _three_points_in_disk(x[i], y[i], x[i2], y[i2], x[i3], y[i3], radius1):
            return True
    return False


def _lic10(x: List[float], y: List[float], n: int, c_pts: int, d_pts: int, epsilon: float) -> bool:
    if n < 5:
        return False
    for i in range(n - c_pts - d_pts - 2):
        ax, ay = x[i], y[i]
        vx, vy = x[i + c_pts + 1], y[i + c_pts + 1]
        bx, by = x[i + c_pts + d_pts + 2], y[i + c_pts + d_pts + 2]
        if (
            realcompare(ax, vx) == "EQ"
            and realcompare(ay, vy) == "EQ"
            or realcompare(bx, vx) == "EQ"
            and realcompare(by, vy) == "EQ"
        ):
            continue
        ang = _angle_at_vertex(ax, ay, vx, vy, bx, by)
        if realcompare(ang, PI - epsilon) == "LT" or realcompare(ang, PI + epsilon) == "GT":
            return True
    return False


def _lic11(x: List[float], y: List[float], n: int, e_pts: int, f_pts: int, area1: float) -> bool:
    if n < 5:
        return False
    for i in range(n - e_pts - f_pts - 2):
        i2 = i + e_pts + 1
        i3 = i + e_pts + f_pts + 2
        a = _triangle_area(x[i], y[i], x[i2], y[i2], x[i3], y[i3])
        if realcompare(a, area1) == "GT":
            return True
    return False


def _lic12(x: List[float], y: List[float], n: int, g_pts: int) -> bool:
    if n < 3:
        return False
    for i in range(n - g_pts - 1):
        j = i + g_pts + 1
        if realcompare(x[j] - x[i], 0.0) == "LT":
            return True
    return False


def _lic13(
    x: List[float], y: List[float], n: int, k_pts: int, length1: float, length2: float
) -> bool:
    if n < 3:
        return False
    gt_len1 = False
    lt_len2 = False
    for i in range(n - k_pts - 1):
        j = i + k_pts + 1
        d = _dist(x[i], y[i], x[j], y[j])
        if realcompare(d, length1) == "GT":
            gt_len1 = True
        if realcompare(d, length2) == "LT":
            lt_len2 = True
        if gt_len1 and lt_len2:
            return True
    return False


def _lic14(
    x: List[float],
    y: List[float],
    n: int,
    a_pts: int,
    b_pts: int,
    radius1: float,
    radius2: float,
) -> bool:
    if n < 5:
        return False
    not_r1 = False
    in_r2 = False
    for i in range(n - a_pts - b_pts - 2):
        i2 = i + a_pts + 1
        i3 = i + a_pts + b_pts + 2
        if not _three_points_in_disk(x[i], y[i], x[i2], y[i2], x[i3], y[i3], radius1):
            not_r1 = True
        if _three_points_in_disk(x[i], y[i], x[i2], y[i2], x[i3], y[i3], radius2):
            in_r2 = True
        if not_r1 and in_r2:
            return True
    return False


def _lic15(
    x: List[float], y: List[float], n: int, e_pts: int, f_pts: int, area1: float, area2: float
) -> bool:
    if n < 5:
        return False
    gt_a1 = False
    lt_a2 = False
    for i in range(n - e_pts - f_pts - 2):
        i2 = i + e_pts + 1
        i3 = i + e_pts + f_pts + 2
        a = _triangle_area(x[i], y[i], x[i2], y[i2], x[i3], y[i3])
        if realcompare(a, area1) == "GT":
            gt_a1 = True
        if realcompare(a, area2) == "LT":
            lt_a2 = True
        if gt_a1 and lt_a2:
            return True
    return False


def decide(
    numpoints: int,
    x: List[float],
    y: List[float],
    parameters: Dict[str, Any],
    lcm: List[List[str]],
    pum_diag: List[bool],
) -> Tuple[List[bool], List[List[bool]], List[bool], bool]:
    p = parameters
    cmv = [
        _lic1(x, y, numpoints, p["LENGTH1"]),
        _lic2(x, y, numpoints, p["RADIUS1"]),
        _lic3(x, y, numpoints, p["EPSILON"]),
        _lic4(x, y, numpoints, p["AREA1"]),
        _lic5(x, y, numpoints, p["Q_PTS"], p["QUADS"]),
        _lic6(x, y, numpoints),
        _lic7(x, y, numpoints, p["N_PTS"], p["DIST"]),
        _lic8(x, y, numpoints, p["K_PTS"], p["LENGTH1"]),
        _lic9(x, y, numpoints, p["A_PTS"], p["B_PTS"], p["RADIUS1"]),
        _lic10(x, y, numpoints, p["C_PTS"], p["D_PTS"], p["EPSILON"]),
        _lic11(x, y, numpoints, p["E_PTS"], p["F_PTS"], p["AREA1"]),
        _lic12(x, y, numpoints, p["G_PTS"]),
        _lic13(x, y, numpoints, p["K_PTS"], p["LENGTH1"], p["LENGTH2"]),
        _lic14(x, y, numpoints, p["A_PTS"], p["B_PTS"], p["RADIUS1"], p["RADIUS2"]),
        _lic15(x, y, numpoints, p["E_PTS"], p["F_PTS"], p["AREA1"], p["AREA2"]),
    ]

    pum: List[List[bool]] = [[False] * 15 for _ in range(15)]
    for i in range(15):
        pum[i][i] = pum_diag[i]
    for i in range(15):
        for j in range(15):
            if i == j:
                continue
            conn = lcm[i][j]
            if conn == "NOTUSED":
                pum[i][j] = True
            elif conn == "ANDD":
                pum[i][j] = cmv[i] and cmv[j]
            else:
                pum[i][j] = cmv[i] or cmv[j]

    fuv: List[bool] = []
    for i in range(15):
        row_all = all(pum[i][k] for k in range(15))
        fuv.append((not pum[i][i]) or row_all)

    launch = all(fuv)
    return cmv, pum, fuv, launch
